static uint32_t s_rerollHunt = 0, s_rerollHuntFail = 0, s_rerollTravel = 0, s_rerollTravelSame = 0;
static uint32_t s_rerollCityWalk = 0, s_rerollTotal = 0;
// Player-proximity weighting telemetry (2026-06-15). Reset in the 60s [PROXBIAS] summary.
