// Shared library factory functions — called by BotEngineLoader via dlsym
// ============================================================================

extern "C" {
	IBotEngine* createBotEngine() {
		return new BotEngine();
	}

	void destroyBotEngine(IBotEngine* engine) {
		delete engine;
	}
}
